import { Light } from "three/src/lights/Light.js";
import Node from "../core/Node.js";
import NodeBuilder from "three/src/nodes/core/NodeBuilder.js";
import LightingNode from "three/src/nodes/lighting/LightingNode.js";
import { DirectLightData, DirectRectAreaLightData } from "three/src/nodes/lighting/LightsNode.js";
import ShadowNode from "three/src/nodes/lighting/ShadowNode.js";

declare module "../../lights/LightShadow.js" {
    interface LightShadow {
        shadowNode?: Node;
    }
}

declare class AnalyticLightNode<T extends Light> extends LightingNode {
    light: T | null;

    constructor(light?: T | null);

    disposeShadow(): void;

    getLightVector(builder: NodeBuilder): Node;

    setupDirect(builder: NodeBuilder): DirectLightData | undefined;

    setupDirectRectArea(builder: NodeBuilder): DirectRectAreaLightData | undefined;

    setupShadowNode(): ShadowNode;

    setupShadow(builder: NodeBuilder): void;
}

export default AnalyticLightNode;
